import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is an FHA loan?", a: "An FHA loan is a mortgage insured by the Federal Housing Administration and designed to help buyers qualify with lower down payments and flexible credit rules." },
  { q: "What is the minimum down payment for an FHA loan?", a: "Many FHA borrowers can put down as little as 3.5% when they meet credit and program requirements." },
  { q: "What is MIP on an FHA loan?", a: "MIP is mortgage insurance premium. FHA loans typically include both upfront MIP and monthly annual MIP." },
  { q: "What credit score do you need for an FHA loan?", a: "FHA guidelines may allow scores as low as 580 with 3.5% down, or 500 with 10% down, but lenders can set stricter overlays." },
  { q: "When does FHA MIP go away?", a: "For many FHA loans with less than 10% down, annual MIP lasts for the life of the loan. With 10% down, it may end after 11 years." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function pmt(principal: number, rate: number, years: number) { const r = rate / 100 / 12; const n = years * 12; return r === 0 ? principal / n : principal * r / (1 - Math.pow(1 + r, -n)); }
function fha(home: number, downPct: number, rate: number, years = 30) { const down = home * downPct / 100; const base = home - down; const upfrontMip = base * 0.0175; const loan = base + upfrontMip; const principalInterest = pmt(loan, rate, years); const mipMonthly = base * 0.0055 / 12; return { down, base, upfrontMip, loan, principalInterest, mipMonthly, total: principalInterest + mipMonthly }; }
function conventional(home: number, downPct: number, rate: number, years = 30) { const down = home * downPct / 100; const loan = home - down; const pi = pmt(loan, rate, years); const pmi = downPct < 20 ? loan * 0.006 / 12 : 0; return { down, loan, pi, pmi, total: pi + pmi }; }

export default function FHALoanCalculator() {
  useCurrencyVersion();
  const [home, setHome] = useState(300000);
  const [downPct, setDownPct] = useState(3.5);
  const [years, setYears] = useState(30);
  const [rate, setRate] = useState(6.5);
  const [score, setScore] = useState("580+");
  const result = useMemo(() => fha(home, Math.max(3.5, downPct), rate, years), [home, downPct, rate, years]);
  const rows = [
    ["FHA 3.5% down", "3.5%", "580", fha(300000, 3.5, 6.5).mipMonthly, fha(300000, 3.5, 6.5).total],
    ["FHA 10% down", "10%", "500", fha(300000, 10, 6.5).mipMonthly, fha(300000, 10, 6.5).total],
    ["Conventional 5% down", "5%", "620", conventional(300000, 5, 6.5).pmi, conventional(300000, 5, 6.5).total],
    ["Conventional 20% down", "20%", "620", conventional(300000, 20, 6.5).pmi, conventional(300000, 20, 6.5).total],
  ] as const;
  return (
    <>
      <SEOHead title="Free FHA Loan Calculator Online - Calculate FHA Loan Payments and MIP Instantly | CalcHive" description="Free online FHA loan calculator. Calculate FHA loan monthly payments including mortgage insurance premium (MIP) and compare to conventional loans instantly. 100% free, no signup required." canonical="/fha-loan-calculator" keywords="free FHA loan calculator, FHA mortgage calculator free online, FHA loan payment calculator free, calculate FHA loan MIP free, FHA vs conventional calculator free" category="Financial Calculators" breadcrumbName="Free FHA Loan Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free FHA Loan Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate FHA payments with upfront MIP, monthly MIP, and conventional loan comparisons.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Home price</label><input type="number" value={home} onChange={(e) => setHome(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Down payment (%)</label><input type="number" value={downPct} onChange={(e) => setDownPct(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Loan term years</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Credit score range</label><select value={score} onChange={(e) => setScore(e.target.value)} className={inputClass}><option>580+</option><option>500-579</option><option>620+</option><option>740+</option></select></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly FHA Payment with MIP</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.total)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Upfront MIP</p><p className="text-lg font-extrabold text-foreground">{money(result.upfrontMip)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Monthly MIP</p><p className="text-lg font-extrabold text-foreground">{money(result.mipMonthly)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total loan amount</p><p className="text-lg font-extrabold text-foreground">{money(result.loan)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate FHA Loan Payments and MIP for Free</h2><p className="text-muted-foreground leading-relaxed">FHA payments include principal, interest, upfront MIP rolled into the loan, and monthly mortgage insurance premium.</p><h2 className="text-2xl font-bold text-foreground">FHA Loan vs Conventional Loan - Which Is Better for You</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">FHA vs Conventional Loan Comparison - $300,000 Home</caption><thead className="bg-muted/60"><tr>{["Loan Type", "Min Down Payment", "Min Credit Score", "MIP/PMI Monthly", "Total Monthly Cost", "Total Cost Over 30yr"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row[0]}><td className="py-2.5 px-3 font-semibold">{row[0]}</td><td className="py-2.5 px-3">{row[1]}</td><td className="py-2.5 px-3">{row[2]}</td><td className="py-2.5 px-3">{money(row[3])}</td><td className="py-2.5 px-3">{money(row[4])}</td><td className="py-2.5 px-3">{money(row[4] * 360)}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free FHA Mortgage Calculator for First-Time Buyers</h2><p className="text-muted-foreground leading-relaxed">Use this as a planning estimate before comparing official lender quotes and FHA program details.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/fha-loan-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


